int plp_aperta2_portmod_port_speed_ability_local_get(int unit, int port, int max_num_abilities, portmod_port_speed_ability_t* abilities, int* num_abilities)
{

    portmod_dispatch_type_t __type__;
    int __rv__;        
    
    
    if(abilities == NULL) {
        APERTA2_SOC_EXIT_WITH_ERR(PHYMOD_E_PARAM, ("abilities NULL parameter"));
    }
    if(PHYMOD_E_NONE != plp_aperta2_portmod_port_speed_ability_t_init(unit, abilities)) {
        APERTA2_SOC_EXIT_WITH_ERR(PHYMOD_E_PARAM, ("abilities initialization failed"));
    }

    if(num_abilities == NULL) {
        APERTA2_SOC_EXIT_WITH_ERR(PHYMOD_E_PARAM, ("num_abilities NULL parameter"));
    }
    /* Dispatch */
    PHYMOD_IF_ERR_RETURN(plp_aperta2_portmod_port_pm_type_get(unit, port, &__type__));
    if(__type__ >= portmodDispatchTypeCount) { 
        APERTA2_SOC_EXIT_WITH_ERR(PHYMOD_E_PARAM, ("Driver is out of range"));
    }

    if(NULL != __plp_aperta2_portmod__dispatch__[__type__]->f_portmod_port_speed_ability_local_get) {
        struct pm_info_s pm_info_tmp; pm_info_t pm_info = &pm_info_tmp;
        PHYMOD_IF_ERR_RETURN(plp_aperta2_portmod_pm_info_get(unit, port, &pm_info));
        port = port & 0xFFFF;
        __rv__ = __plp_aperta2_portmod__dispatch__[__type__]->f_portmod_port_speed_ability_local_get(unit, port, pm_info, max_num_abilities, abilities, num_abilities);
        PHYMOD_IF_ERR_RETURN(__rv__);
    } else { 
        APERTA2_SOC_EXIT_WITH_ERR(PHYMOD_E_UNAVAIL, ("plp_aperta2_portmod_port_speed_ability_local_get isn't implemented for driver type"));
    }
        

    return PHYMOD_E_NONE;
    
}


